args.sparql:
SELECT DISTINCT ?conference ?conferenceLabel WHERE {
  ?team wdt:P2892 "1889" ;
        wdt:P471 ?conference ;
        pq:P580 ?startTime .
  ?conference rdfs:label ?conferenceLabel .
  FILTER(langMatches(LANG(?conferenceLabel), "en"))
  FILTER(year(?startTime) = 1988)
  FILTER NOT EXISTS { ?conference wdt:P1412 ?div }  
}

SELECT DISTINCT ?conference ?conferenceLabel WHERE {
  ?team wdt:P571 ?inception ;
        p:P471 ?statement .
  FILTER (year(?inception) = 1889)
  ?statement ps:P471 ?conference ;
            pq:P580 ?startYear ;
            OPTIONAL { pq:P582 ?endYear } .
  FILTER (year(?startYear) <= 1988)
  FILTER (year(?endYear) >= 1988 || !bound(?endYear))
  ?conference wdt:P361 wd:Q22829196 .
  ?conference rdfs:label ?conferenceLabel .
  FILTER (langMatches(LANG(?conferenceLabel), "en"))
}

SELECT DISTINCT ?conference ?conferenceLabel WHERE {
  ?team wdt:P31 wd:Q454654 ;
        wdt:P571 ?inception .
  FILTER (YEAR(?inception) = 1889)
  ?team p:P471 ?statement .
  ?statement ps:P471 ?conference ;
             pq:P580 ?start .
  OPTIONAL { ?statement pq:P582 ?end } .
  FILTER (YEAR(?start) <= 1988)
  FILTER (YEAR(?end) >= 1988 || !BOUND(?end))
  ?conference wdt:P361 wd:Q22829196 ;
             wdt:P1340 wd:Q25790659 .
  ?conference rdfs:label ?conferenceLabel .
  FILTER (LANG(?conferenceLabel) = "en")
}
